<?php require_once __DIR__ . '/../../controllers/marketing_subscriptionsController.php'; require_once __DIR__ . '/marketing_helpers.php'; $statuses=['requested','meeting_scheduled','approved_manually','pending_payment','active','paused','completed','cancelled']; ?>
<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Marketing - Solicitudes</title><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link rel="stylesheet" href="../../assets/framework/framework.css"><script src="../../assets/framework/framework.js" defer></script><link rel="stylesheet" href="marketing_styles.css"></head><body><div class="layout"><?php require __DIR__ . '/../../partials/marketing_nav.php'; ?><main class="main"><header class="navbar"><div class="navbar-left"><button class="btn-icon" onclick="toggleSidebar()"><span class="material-icons">menu</span></button><div class="navbar-title">Solicitudes de planes</div></div><?= renderBotonPerfil($perfil['avatar_path'] ?? ($_SESSION['avatar_path'] ?? null)) ?></header><section class="content page-stack"><?php if (($flash['message'] ?? '') !== ''): ?><div class="flash <?= mh($flash['type']) ?>"><?= mh($flash['message']) ?></div><?php endif; ?><div class="marketing-card"><h2>Solicitudes y contrataciones</h2><div class="table-wrap"><table class="marketing-table"><thead><tr><th>Usuario</th><th>Plan</th><th>Valor</th><th>Estado</th><th>Responsable y fechas</th><th>Actualizar</th></tr></thead><tbody><?php foreach ($suscripciones as $s): ?><tr><td><strong><?= mh($s['user_label'] ?? '') ?></strong><br><?= mh($s['user_email'] ?? '') ?><br><?= mh($s['user_whatsapp'] ?? '') ?></td><td><?= mh($s['plan_name'] ?? '') ?><br><?= (int)$s['duration_months'] ?> meses</td><td><?= money($s['monthly_price'] ?? 0) ?>/mes<br>Total <?= money($s['total_contract_value'] ?? 0) ?></td><td><?= statusLabel($s['status'] ?? '') ?></td><td><?= mh($s['marketing_label'] ?? '-') ?><br><?= dateLabel($s['start_date'] ?? '') ?> - <?= dateLabel($s['end_date'] ?? '') ?></td><td><form method="post" class="form-grid"><input type="hidden" name="action" value="update_subscription"><input type="hidden" name="id" value="<?= (int)$s['id'] ?>"><select name="status"><?php foreach($statuses as $st): ?><option value="<?= $st ?>" <?= ($s['status'] ?? '')===$st?'selected':'' ?>><?= statusLabel($st) ?></option><?php endforeach; ?></select><select name="assigned_marketing_user_id"><option value="">Responsable</option><?php foreach($responsables as $r): ?><option value="<?= (int)$r['id'] ?>" <?= (int)($s['assigned_marketing_user_id'] ?? 0)===(int)$r['id']?'selected':'' ?>><?= mh($r['display_name']) ?></option><?php endforeach; ?></select><input type="number" step="0.01" name="monthly_ad_budget" value="<?= mh($s['monthly_ad_budget'] ?? '') ?>" placeholder="Presupuesto ads"><input type="date" name="start_date" value="<?= mh($s['start_date'] ?? '') ?>"><input type="date" name="end_date" value="<?= mh($s['end_date'] ?? '') ?>"><textarea name="notes" placeholder="Notas"><?= mh($s['notes'] ?? '') ?></textarea><button class="btn btn-aceptar" type="submit">Guardar</button></form></td></tr><?php endforeach; ?></tbody></table></div><?php if(empty($suscripciones)): ?><div class="empty">No hay solicitudes.</div><?php endif; ?></div></section></main></div><?php $perfilObligatorio=false; require_once __DIR__ . '/../../partials/modal_perfil/modal_perfil.php'; ?></body></html>
